345→/**
346→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
347→ * the boundary nodes [from] or [to] contains a newline.
348→ */
349→public fun hasNewLineInClosedRange(
350→    from: ASTNode,
351→    to: ASTNode,
352→): Boolean =
353→    from.isWhiteSpaceWithNewline() ||
354→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
355→        to.isWhiteSpaceWithNewline()
356→
357→/**
358→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
359→ * should not contain a newline.
360→ */
361→public fun noNewLineInClosedRange(
362→    from: ASTNode,
363→    to: ASTNode,
364→): Boolean =
365→    !from.isWhiteSpaceWithNewline() &&
366→        leavesInOpenRange(from, to).none { it.textContains('\n') } &&
367→        !to.isWhiteSpaceWithNewline()
368→
369→/**
370→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
371→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
372→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
373→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
374→ */
375→public fun leavesInOpenRange(
376→    from: ASTNode,
377→    to: ASTNode,
378→): Sequence<ASTNode> =
379→    from
380→        .leaves()
381→        .takeWhile { it != to && it != to.firstChildNode }
