385→/**
386→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
387→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
388→ */
389→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
390→    val sequence =
391→        if (isLeaf()) {
392→            sequenceOf(this)
393→        } else {
394→            emptySequence()
395→        }
396→    return sequence.plus(leaves(forward))
397→}
