 27→public class NoSemicolonsRule : StandardRule("no-semi") {
 28→    override fun beforeVisitChildNodes(
 29→        node: ASTNode,
 30→        autoCorrect: Boolean,
 31→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 32→    ) {
 33→        if (node.elementType != SEMICOLON) {
 34→            return
 35→        }
 36→        val nextLeaf = node.nextLeaf()
 37→        val prevCodeLeaf = node.prevCodeLeaf()
 38→        if (nextLeaf.doesNotRequirePreSemi() && isNoSemicolonRequiredAfter(node)) {
 39→            emit(node.startOffset, "Unnecessary semicolon", true)
 40→            if (autoCorrect) {
 41→                val prevLeaf = node.prevLeaf(true)
 42→                node.treeParent.removeChild(node)
 43→                if (prevLeaf.isWhiteSpace() && (nextLeaf == null || nextLeaf.isWhiteSpace())) {
 44→                    node.treeParent.removeChild(prevLeaf!!)
 45→                }
 46→            }
 47→        } else if (nextLeaf !is PsiWhiteSpace) {
 48→            val prevLeaf = node.prevLeaf()
 49→            if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) { // \n;{
 50→                return
 51→            }
 52→            // todo: move to a separate rule
 53→            emit(node.startOffset + 1, "Missing spacing after \";\"", true)
 54→            if (autoCorrect) {
 55→                node.upsertWhitespaceAfterMe(" ")
 56→            }
 57→        }
 58→    }
 59→
 60→    private fun ASTNode?.doesNotRequirePreSemi(): Boolean {
 61→        if (this == null) {
 62→            return true
 63→        }
 64→        if (this is PsiWhiteSpace) {
 65→            val nextLeaf = nextLeaf {
 66→                val psi = it.psi
 67→                it !is PsiWhiteSpace && it !is PsiComment && psi.getStrictParentOfType<KDoc>() == null &&
 68→                    psi.getStrictParentOfType<KtAnnotationEntry>() == null
 69→            }
 70→            return (
 71→                nextLeaf == null || // \s+ and then eof
 72→                    textContains('\n') && nextLeaf.elementType != KtTokens.LBRACE
 73→                )
 74→        }
 75→        return false
 76→    }
 77→
 78→    private fun isNoSemicolonRequiredAfter(node: ASTNode): Boolean {
 79→        val prevCodeLeaf =
 80→            node.prevCodeLeaf()
 81→                ?: return true
 82→        if (prevCodeLeaf.elementType == OBJECT_KEYWORD) {
 83→            // https://github.com/pinterest/ktlint/issues/281
 84→            return false
 85→        }
 86→
 87→        val parent = prevCodeLeaf.treeParent?.psi
 88→        if (parent is KtLoopExpression && parent !is KtDoWhileExpression && parent.body == null) {
 89→            // https://github.com/pinterest/ktlint/issues/955
 90→            return false
 91→        }
 92→        if (parent is KtIfExpression && parent.then == null) {
 93→            return false
 94→        }
 95→        // In case of an enum entry the semicolon (e.g. the node) is a direct child node of enum entry
 96→        if (node.treeParent.elementType == ENUM_ENTRY) {
 97→            return node.isLastCodeLeafBeforeClosingOfClassBody()
 98→        }
 99→
100→        return true
101→    }
102→
103→    private fun ASTNode?.isLastCodeLeafBeforeClosingOfClassBody() = getLastCodeLeafBeforeClosingOfClassBody() == this
104→
105→    private fun ASTNode?.getLastCodeLeafBeforeClosingOfClassBody() =
106→        this
107→            ?.parent(CLASS_BODY)
108→            ?.lastChildLeafOrSelf()
109→            ?.prevCodeLeaf()
110→}
